const rows = $input.all();
if (rows.length === 0 || !rows[0].json.assigned_agent) {
  return { has_issues: false, report: 'No flagged outputs this week. All agents performing well.' };
}

const summary = rows.map(r =>
  `• ${r.json.assigned_agent}: ${r.json.flagged_count} flagged, avg score ${r.json.avg_score}/5`
).join('\n');

return {
  has_issues: true,
  agents_with_issues: rows.map(r => r.json.assigned_agent),
  report: summary,
  flagged_data: rows.map(r => r.json)
};
